// ── GRADES ───────────────────────────────────────────────────────────────────
const GRADES = {
  Healthy: { color: '#22c55e', bg: 'rgba(34,197,94,.15)', range: '85–100' },
  Stable: { color: '#84cc16', bg: 'rgba(132,204,22,.15)', range: '70–84' },
  Warning: { color: '#f59e0b', bg: 'rgba(245,158,11,.15)', range: '50–69' },
  Critical: { color: '#ef4444', bg: 'rgba(239,68,68,.15)', range: '30–49' },
  Emergency: { color: '#7c3aed', bg: 'rgba(124,58,237,.15)', range: '<30' },
};

function grade(s) {
  return s >= 85 ? 'Healthy' : s >= 70 ? 'Stable' : s >= 50 ? 'Warning' : s >= 30 ? 'Critical' : 'Emergency';
}

function clamp(v, lo = 0, hi = 100) {
  return Math.max(lo, Math.min(hi, v));
}

