// ── RUL CALCULATOR ────────────────────────────────────────────────────────────
function calcRUL(health, dl, iy) {
  const yr = new Date().getFullYear();
  const rate = (100 / dl) * 1.1 * 1.05 * 0.9;
  const rul = Math.max(0, (health - 50) / rate);
  return {
    rul: Math.round(rul),
    cy: yr + Math.round(rul),
    conf: health > 70 ? 'High confidence (±2 yrs)' : health > 50 ? 'Medium confidence (±5 yrs)' : 'Low confidence (±10 yrs)',
  };
}
